using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { EnableCaching = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://app/feature/{featureName}",
        Name = "Feature Flag",
        MimeType = "application/json"),
     Description("Returns the status of a specific feature flag.")]
    public static string GetFeatureFlag(
        [Description("Name of the feature flag to check")] string featureName)
    {
        var flags = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
        {
            ["EnableCaching"] = true,
            ["EnableLogging"] = true,
            ["BetaFeatures"] = false,
        };

        var result = new
        {
            Feature = featureName,
            Enabled = flags.TryGetValue(featureName, out var enabled) && enabled,
            Found = flags.ContainsKey(featureName)
        };

        return JsonSerializer.Serialize(result, JsonOptions);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes the input message back, optionally in uppercase.")]
    public static string Echo(
        [Description("The message to echo back")] string message,
        [Description("If true, converts the message to uppercase")] bool uppercase = false)
    {
        return uppercase ? message.ToUpperInvariant() : message;
    }

    [McpServerTool, Description("Returns the current server date and time in UTC.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("O");
    }
}

